1650	% SOURCE QUOTE PROOF: "The intersection of the diagonal of $\grass(r,d)$ with
1651	% $U^I\times U^J$ can be seen to be the closed subscheme
1652	% $\Delta_{I,J}\subset U^I\times U^J$ defined by entries of the matrix formula
1653	% $X^J_I\,X^I - X^J =0$, and so $\grass(r,d)$ is a separated scheme."
1654	% (references/nitsure-hilbert-quot-src/nitsure-hilbert-quot.tex, L856-L860.)
1655	\begin{proof}
1656	  \uses{def:gr_glued_scheme, def:gr_transition}
1657	  The products \(U^I \times_{\mathbb{Z}} U^J\), as \(I, J\) range over the
1658	  size-\(d\) subsets, form an affine open cover of \(\mathrm{Gr}(r,d)
1659	  \times_{\mathbb{Z}} \mathrm{Gr}(r,d)\). Separatedness may be checked on this
1660	  cover: it suffices to show that for each pair \((I,J)\) the preimage
1661	  \(\Delta^{-1}(U^I \times_{\mathbb{Z}} U^J)\) maps by a closed immersion into
1662	  \(U^I \times_{\mathbb{Z}} U^J\), i.e.\ that the corresponding ring
1663	  homomorphism is surjective.
1664	
1665	  By \cref{def:gr_glued_scheme} the diagonal preimage is the overlap
1666	  \(\Delta^{-1}(U^I \times_{\mathbb{Z}} U^J) = U^I \cap U^J = U^I_J = \Spec
1667	  \mathbb{Z}[X^I, 1/P^I_J]\). The restricted diagonal corresponds to the ring map
1668	  \[
1669	    \delta_{I,J} : \mathbb{Z}[X^I] \otimes_{\mathbb{Z}} \mathbb{Z}[X^J]
1670	    \longrightarrow \mathbb{Z}[X^I, 1/P^I_J],
1671	    \qquad
1672	    X^I \otimes 1 \mapsto X^I, \quad 1 \otimes X^J \mapsto (X^I_J)^{-1} X^I,
1673	  \]
1674	  the second component being the comorphism \(\theta_{I,J}\) of
1675	  \cref{def:gr_transition} (a point of \(U^I_J\) and its image under
1676	  \(\theta_{I,J}\) are the two coordinates of a point of the diagonal). We claim
1677	  \(\delta_{I,J}\) is surjective. Its image contains all entries of \(X^I\)
1678	  (from the first factor). From the second factor it contains the entries of
1679	  \((X^I_J)^{-1} X^I\); taking the \(I\)-minor of this matrix, and using
1680	  \(X^I_I = 1_{d\times d}\), the image contains the entries of \((X^I_J)^{-1}\),
1681	  and in particular
1682	  \[
1683	    \delta_{I,J}(1 \otimes P^J_I) = \det\bigl((X^I_J)^{-1}\bigr) = 1/P^I_J .
1684	  \]
